const parent = document.getElementById('viz');
const host = document.createElement('div'); host.style.cssText='display:block;width:100%';
const root = host.attachShadow({mode:'open'});
const CSS = `
:host{display:block;width:100%;--_bg:var(--ov-bg,#fff);--_raised:var(--ov-bg,#fff);--_text:var(--ov-text,#1f2933);--_muted:var(--ov-muted,#6b7280);--_line:var(--ov-line,#e5e7eb);--_accent:var(--ov-accent,#4f46e5);--_ok:var(--ov-ok,#0f9d58);--_no:var(--ov-no,#e11d48);--_partial:var(--ov-partial,#d97706);--_soft:#f8fafc;color:var(--_text);font-family:ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;-webkit-font-smoothing:antialiased}
:host([hidden]){display:none}
*{box-sizing:border-box}
.frame{overflow:hidden;border:1px solid var(--_line);border-radius:18px;background:var(--_bg);box-shadow:0 12px 32px rgba(15,23,42,.07)}
.heading{padding:22px 24px 20px;border-bottom:1px solid var(--_line);background:var(--_soft)}
.eyebrow{margin:0 0 6px;color:var(--_accent);font-size:11px;font-weight:800;letter-spacing:.13em;text-transform:uppercase}
h2{margin:0;color:var(--_text);font-size:clamp(20px,3vw,27px);font-weight:750;letter-spacing:-.025em;line-height:1.2}
.summary{max-width:760px;margin:7px 0 0;color:var(--_muted);font-size:13px;line-height:1.5}
.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:1px;background:var(--_line)}
.quadrant{position:relative;min-height:210px;padding:22px 24px 24px;background:color-mix(in srgb,var(--tone) 6%,var(--_bg))}
.quadrant::before{content:"";position:absolute;inset:0 auto 0 0;width:4px;background:var(--tone)}
.qhead{display:flex;align-items:center;gap:11px;margin-bottom:16px}
.icon{display:grid;width:34px;height:34px;flex:0 0 auto;place-items:center;border-radius:11px;background:color-mix(in srgb,var(--tone) 14%,var(--_bg));color:var(--tone);font-size:17px;font-weight:850}
.label{color:var(--_text);font-size:16px;font-weight:780;letter-spacing:-.012em}
.hint{margin-top:2px;color:var(--_muted);font-size:11px;font-weight:650;letter-spacing:.04em;text-transform:uppercase}
ul{display:grid;gap:10px;margin:0;padding:0;list-style:none}
li{position:relative;padding-left:18px;color:var(--_text);font-size:13px;line-height:1.48}
li::before{content:"";position:absolute;left:1px;top:.55em;width:7px;height:7px;border-radius:999px;background:var(--tone);box-shadow:0 0 0 4px color-mix(in srgb,var(--tone) 12%,transparent)}
.strengths{--tone:var(--_ok)}.weaknesses{--tone:var(--_no)}.opportunities{--tone:var(--_accent)}.threats{--tone:var(--_partial)}
.empty{color:var(--_muted);font-style:italic}
@media (max-width:620px){.heading{padding:18px}.grid{grid-template-columns:1fr}.quadrant{min-height:0;padding:20px 20px 22px}}
@media (prefers-color-scheme:dark){:host{--_bg:var(--ov-bg,#0f172a);--_raised:var(--ov-bg,#111827);--_text:var(--ov-text,#e5e7eb);--_muted:var(--ov-muted,#9ca3af);--_line:var(--ov-line,#293548);--_accent:var(--ov-accent,#818cf8);--_ok:var(--ov-ok,#34d399);--_no:var(--ov-no,#fb7185);--_partial:var(--ov-partial,#fbbf24);--_soft:#111827}.frame{box-shadow:0 14px 34px rgba(0,0,0,.28)}}
`;
const sheet = new CSSStyleSheet(); sheet.replaceSync(CSS); root.adoptedStyleSheets=[sheet];
const make=(tag,className,text)=>{const node=document.createElement(tag);if(className)node.className=className;if(text!==undefined)node.textContent=text;return node;};
const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'SWOT analysis';
const frame=make('section','frame');frame.setAttribute('aria-label',title);
const heading=make('header','heading');heading.appendChild(make('div','eyebrow','Strategic snapshot'));heading.appendChild(make('h2','',title));
if(data.summary)heading.appendChild(make('p','summary',String(data.summary)));frame.appendChild(heading);
const grid=make('div','grid');
[
  ['strengths','Strengths','S','Internal advantages'],
  ['weaknesses','Weaknesses','W','Internal constraints'],
  ['opportunities','Opportunities','O','External upside'],
  ['threats','Threats','T','External risks']
].forEach(([key,label,icon,hint])=>{
  const card=make('section','quadrant '+key);card.setAttribute('aria-label',label);
  const qhead=make('div','qhead');qhead.appendChild(make('span','icon',icon));
  const names=make('div');names.appendChild(make('div','label',label));names.appendChild(make('div','hint',hint));qhead.appendChild(names);card.appendChild(qhead);
  const list=make('ul');const values=Array.isArray(data[key])?data[key]:[];
  if(values.length){values.forEach(value=>list.appendChild(make('li','',String(value))));}else{list.appendChild(make('li','empty','No items supplied'));}
  card.appendChild(list);grid.appendChild(card);
});
frame.appendChild(grid);root.appendChild(frame);
parent.appendChild(host);

